import{_ as e}from"./chunks/plugin-vue_export-helper.DlAUqK2U.js";import{o,c as p,a as i}from"./chunks/runtime-core.esm-bundler.DWBnY2hA.js";const d=JSON.parse('{"title":"О влиянии","description":"","frontmatter":{"title":"О влиянии","date":"2022-06-14T00:00:00.000Z","head":[["link",{"rel":"canonical","href":"https://alterfo.github.io/posts/2022-06-14-impact"}],["meta",{"property":"og:type","content":"article"}],["meta",{"property":"og:title","content":"О влиянии"}],["meta",{"property":"og:description","content":"Oleg Sidorkin — инженер и музыкант. Проекты, инструменты и заметки."}],["meta",{"property":"og:url","content":"https://alterfo.github.io/posts/2022-06-14-impact"}],["meta",{"property":"og:image","content":"https://alterfo.github.io/og.png"}],["meta",{"property":"og:site_name","content":"Alterfo"}],["meta",{"property":"og:locale","content":"ru_RU"}],["meta",{"name":"twitter:card","content":"summary_large_image"}],["meta",{"name":"twitter:title","content":"О влиянии"}],["meta",{"name":"twitter:description","content":"Oleg Sidorkin — инженер и музыкант. Проекты, инструменты и заметки."}],["meta",{"name":"twitter:image","content":"https://alterfo.github.io/og.png"}],["script",{"type":"application/ld+json"},"{\\"@context\\":\\"https://schema.org\\",\\"@type\\":\\"BlogPosting\\",\\"headline\\":\\"О влиянии\\",\\"description\\":\\"Oleg Sidorkin — инженер и музыкант. Проекты, инструменты и заметки.\\",\\"url\\":\\"https://alterfo.github.io/posts/2022-06-14-impact\\",\\"inLanguage\\":\\"ru-RU\\",\\"author\\":{\\"@type\\":\\"Person\\",\\"name\\":\\"Oleg Sidorkin\\",\\"alternateName\\":\\"alterfo\\",\\"url\\":\\"https://alterfo.github.io\\",\\"jobTitle\\":\\"Software Engineer\\",\\"knowsAbout\\":[\\"Music\\",\\"Audio DSP\\",\\"AI\\",\\"RAG\\",\\"Frontend Development\\",\\"Solution Architecture\\"],\\"sameAs\\":[\\"https://github.com/alterfo\\"]},\\"datePublished\\":\\"2022-06-14\\"}"]]},"headers":[],"relativePath":"posts/2022-06-14-impact.md","filePath":"posts/2022-06-14-impact.md"}'),a={name:"posts/2022-06-14-impact.md"};function r(n,t,l,s,c,m){return o(),p("div",null,[...t[0]||(t[0]=[i("<p>Основной инструмент лидера команды или формального управленца это другие люди.</p><p>Добиться чего-либо от людей можно только через техники влияния.</p><p>Разделить техники влияния можно на две категории: варварские и цивилизованные.</p><p>Если с цивилизованными всё просто - аргументация и контр-аргументация. С варварскими всё немного сложнее. Их хотелось бы разобрать подробнее.</p><p>Варварские методы:</p><ul><li>угрозы, принуждение, моральное давление</li><li>манипуляции (лесть, ложь)</li><li>нападение: <ul><li>непрошенные советы</li><li>деструктивная критика</li><li>деструктивная констатация</li></ul></li></ul><p>Варварские методы действуют на эмоции, разжигают гнев, злобу, вызывают чувство вины и беспомощности.</p><p>Наиболее эффективный способ отбить нападение - психологическое айкидо.</p><p>Вдох, выдох, - &quot;Да, Игорь, возможно вы правы&quot;</p><p>В особо жарких ситуациях хорошо работает испорченная пластинка - повторять одну и ту же фразу пока человек не успокоится.</p><p>Также можно уточнить - а как бы человек принял решение в этой ситуации.</p><p>Если ваша позиция чуть сильнее - можно объяснить своё поведение личностными качествами.</p><p>В любом случае, важно сразу отбить атаку так, чтобы конфликт не дошёл до точки невозврата - неконтролируемых эмоций.</p><p>Ни в коем случае не оправдываться, не шутить и не говорить снисходительно - это тоже конфликтогены.</p>",14)])])}const _=e(a,[["render",r]]);export{d as __pageData,_ as default};
